class Solution(object):
    def numSmallerByFrequency(self, queries, words):
        def f(s):
            return s.count(min(s))
        word_freq = sorted([f(w) for w in words])
        result = []
        for q in queries:
            freq = f(q)
            count = 0
            for wf in word_freq:
                if wf > freq:
                    count += 1
            result.append(count)
        return result
